    ~Dog() { cout << "~Dog()" << endl; }
    void bark() { cout << name << " barks" << endl; }
};

int main() {
    cout << "--- Creating Dog ---" << endl;
    Dog d("Tommy");
    d.breathe();
    d.feedMilk();
    d.bark();
    cout << "--- Destroying Dog ---" << endl;
    return 0;
}

